var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁- 킁킁-","JPN":"くんーくんくんー","ENG":"*Sniff* *Sniff*","TWN":"嗅——嗅嗅——"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Um...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아까부터 무슨 냄새를 맡고 계신 거죠?","JPN":"さっきから何の匂いを嗅いでるんですか？","ENG":"What are you trying to smell?","TWN":"你從剛才開始就在聞什麼味道？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왠지 이렇게 하면 유대감이 더 잘 느껴지더라고요.","JPN":"なんだかこうすると、連帯感をもっと強く感じられるんです。","ENG":"I feel a stronger sense of the bond when I do this for some reason.","TWN":"總覺得這樣做能更好地感受到彼此的羈絆。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"좀 더 높이 들어주실 수 있나요? 위쪽 바람이 더 잘 부는 것 같은데.","JPN":"もっと高く持ちあげてくれませんか？　上の方がよく風が吹いてるみたいですから。","ENG":"Could you hold me a little higher? I think the wind is blowing better up there.","TWN":"能再舉高一點嗎？上面的風好像更大。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이렇게요?","JPN":"こうですか？","ENG":"Like this?","TWN":"像這樣嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁 킁-","JPN":"くんくんー","ENG":"*Sniff* *Sniff*","TWN":"嗅——嗅——"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그냥 냄새로 찾고 있는 것 같은데…","JPN":"ただ匂いで探してるみたいなんだけど……","ENG":"It just looks like she's trying to find him by scent...","TWN":"好像只是單純在靠氣味找人……"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아무렴 어때. 괜히 지적하지 말자.","JPN":"まあ、いいか。余計なことを言うのはやめとこう。","ENG":"But who cares how? Let's not nitpick right now.","TWN":"但是無所謂啦，這種時候就別太苛求了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"갑자기 안개가 짙어지는군.","JPN":"急に霧が濃くなったな。","ENG":"The fog is getting thicker all of a sudden.","TWN":"霧突然變濃了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이면세계에서 이런 기상이변은 결코 좋은 징조가 아니죠.","JPN":"裏世界でこのような気象異変は決していい前兆ではありません。","ENG":"Unusual weather conditions like this aren't a good sign in the Counterside.","TWN":"這種氣象在異界絕不是什麼好兆頭。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저희와 너무 떨어지지 않게 조심하십시오.","JPN":"私たちとあまり離れないように気をつけてください。","ENG":"Be careful not to be too far away from us.","TWN":"請小心，不要離我們太遠。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…응?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"방금 봤어요? 안개 사이로 사람 형체가 보였는데.","JPN":"今、見ました？　霧の中から人の形が見えたんですけど。","ENG":"Did you see that? I saw a human figure through the fog.","TWN":"你剛剛看到了嗎？霧中有一個人影。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"글쎄요. 발소리 같은 건 전혀 못 들은 것 같…","JPN":"さあ？　足音はまったく聞こえなかったと思う……","ENG":"I don't know. I didn't hear any footsteps–","TWN":"沒有……我好像完全沒聽到腳步聲……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으앗? 폭격?","JPN":"わあっ？　爆撃？","ENG":"What? An explosion?","TWN":"呃啊？子彈？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐야? 왜 갑자기 사방에서 총성이 울리는 거지?","JPN":"何？　どうしていきなり周りから銃声が聞こえるんだろう？","ENG":"Huh? Why do I suddenly hear gunshots ringing everywhere?","TWN":"怎麼了？為什麼突然哪裡都是槍聲……！？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식파 때문인가? 여태 잠잠한 줄 알았던 전쟁 PTSD가 이제 와서 사춘기처럼 폭발한 건가?","JPN":"侵食波のせいかな？　今まで潜在していた戦争のPTSDが今更爆発した？","ENG":"Is it because of the Corruption ray? Or has my war-related PTSD, which was dormant until now, suddenly been triggered like puberty?","TWN":"是因為侵蝕波嗎？還是說我一直以為平靜下來的戰後PTSD，終於像青春期一樣爆發了嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 그렇다기엔…","JPN":"でも、それにしては……","ENG":"But for something like that to happen...","TWN":"但要這麼說的話……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…난 이런 장소는 한 번도 와본 적 없는데?","JPN":"……私、こんな場所には一度も来た覚えがないんだけど？","ENG":"...I've never been to a place like this before.","TWN":"……我從來沒來過這種地方？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"사도가 너무 강해요! 벌써 절반이 당했습니다!","JPN":"使徒が強すぎます！　もう半分がやられました！","ENG":"The Apostle's too strong! Half of our units have already been wiped out!","TWN":"使徒太強了！我們已經損失了一半人手！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"이대로는 승산이 없어.","JPN":"このままだと勝ち目がない。","ENG":"We're all doomed.","TWN":"我們這樣根本沒有勝算。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전대장님께서 말씀하신 차선책대로 해! 최대한 흩어져서 시간을 버는 거다!","JPN":"戦隊長がおっしゃった次善策どおりにしろ！　なるべく散開して時間を稼ぐんだ！","ENG":"Let's do what Commander said and go with Plan B! Everyone, scatter as much as possible to buy the others time!","TWN":"按照隊長說的備用方案行動！分散開來爭取時間！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"군인…?","JPN":"軍人……？","ENG":"Soldiers...?","TWN":"士兵……？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};